import{_ as e,o as d,c as o,a2 as c}from"./chunks/framework.DvFsUg-r.js";const g=JSON.parse('{"title":"검증 규칙 계약","description":"","frontmatter":{"title":"검증 규칙 계약","feature_id":"013","created":"2026-06-03 18:28 (KST)","date":"2026-06-03T00:00:00.000Z"},"headers":[],"relativePath":"specs/013-docs-validation/contracts/validation-rules.md","filePath":"specs/013-docs-validation/contracts/validation-rules.md","lastUpdated":null}'),a={name:"specs/013-docs-validation/contracts/validation-rules.md"};function r(n,t,s,l,i,h){return d(),o("div",null,[...t[0]||(t[0]=[c('<h1 id="contract-검증-규칙-범주별-결정-규칙" tabindex="-1">Contract: 검증 규칙 (범주별 결정 규칙) <a class="header-anchor" href="#contract-검증-규칙-범주별-결정-규칙" aria-label="Permalink to &quot;Contract: 검증 규칙 (범주별 결정 규칙)&quot;">​</a></h1><p>검증기가 적용하는 결정적 규칙. 입출력 픽스처 유닛 테스트의 기준이다.</p><h2 id="대상-범위" tabindex="-1">대상 범위 <a class="header-anchor" href="#대상-범위" aria-label="Permalink to &quot;대상 범위&quot;">​</a></h2><p><strong>포함(C2/C3/C4 정적 검사)</strong>: <code>specs/**/*.md</code>, <code>blog/journal/**/*.md</code>, <code>blog/*.md</code>. <strong>제외</strong>: <code>node_modules/**</code>, <code>blog/.vitepress/{dist,cache}/**</code>, <code>vendor/**</code>, 생성물 <code>blog/specs/**</code>·<code>blog/llm/**</code>·<code>blog/blog-archive/**</code>. <strong>C1(빌드)</strong>: 사이트 전체(sync 후 VitePress 가 렌더하는 모든 페이지).</p><h2 id="c1-—-빌드-유효성-blocking" tabindex="-1">C1 — 빌드 유효성 (blocking) <a class="header-anchor" href="#c1-—-빌드-유효성-blocking" aria-label="Permalink to &quot;C1 — 빌드 유효성 (blocking)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>단계</th><th>동작</th><th>위반 판정</th></tr></thead><tbody><tr><td>sync</td><td>win32=<code>scripts/sync-specs-to-vitepress.ps1</code>, 그 외=<code>.sh</code> 실행</td><td>비0 종료 → C1 위반</td></tr><tr><td>build</td><td><code>npm --prefix blog run build</code></td><td>비0 종료 → C1 위반(파일:라인 추출)</td></tr></tbody></table><ul><li>VitePress strict 가 잡는 것: 깨진 내부 링크, Vue/템플릿 충돌(<code>{{ }}</code>·표 셀 안 꺾쇠 토큰·미닫힘 태그). stderr 에서 <code>file (line:col)</code> 패턴을 추출해 <code>message</code> 로.</li><li><code>--no-build</code> 면 C1 스킵 + 리포트에 &quot;C1 미검증&quot; 명시.</li></ul><h2 id="c2-—-프런트매터-규약-blocking" tabindex="-1">C2 — 프런트매터 규약 (blocking) <a class="header-anchor" href="#c2-—-프런트매터-규약-blocking" aria-label="Permalink to &quot;C2 — 프런트매터 규약 (blocking)&quot;">​</a></h2><p>권위 기준은 <strong>CLAUDE.md 규칙 1</strong>: <code>created</code>(시각 포함)는 <strong>spec.md·저널</strong>의 의무, 저널은 정렬용 <code>date</code>(ISO, <code>created</code> 와 동일 시각) 추가. 보조 산출물(plan/research/ tasks 등)은 필수 필드 강제 대상이 아니다. frontmatter 없는 파일은 <strong>스킵</strong>. <code>created</code> 공통 정규식: <code>^\\d{4}-\\d{2}-\\d{2} \\d{2}:\\d{2} \\(KST\\)$</code>.</p><table tabindex="0"><thead><tr><th>kind</th><th>대상</th><th>필수 필드</th><th>추가</th></tr></thead><tbody><tr><td>spec</td><td><code>specs/*/spec.md</code></td><td>title, feature_id, status, created</td><td><code>created</code> 형식</td></tr><tr><td>spec-aux</td><td>specs 내 기타 frontmatter 보유 .md</td><td>(강제 없음)</td><td><code>created</code> 있으면 형식만</td></tr><tr><td>journal</td><td><code>blog/journal/**</code> 중 <strong>날짜 접두</strong>(<code>YYYY-MM-DD-*.md</code>) 게시글</td><td>title, created, date</td><td><code>date</code> 가 ISO+시각, <code>created</code> 시각과 동일</td></tr><tr><td>content</td><td>그 외(저널 <code>index.md</code> 포함)</td><td>(강제 없음)</td><td>—</td></tr></tbody></table><blockquote><p>저널 디렉터리의 비-날짜 파일(<code>index.md</code> 등)은 <code>content</code> 로 분류해 강제하지 않는다. <code>date</code> 날짜부 ↔ 파일명 접두 일치는 <strong>C3</strong> 가 담당(중복 보고 회피).</p></blockquote><p>위반 예: spec.md 의 <code>created</code> 누락/형식 불일치·feature_id 누락, 저널 <code>date</code>≠<code>created</code> 시각.</p><h2 id="c3-—-정렬·구조-blocking" tabindex="-1">C3 — 정렬·구조 (blocking) <a class="header-anchor" href="#c3-—-정렬·구조-blocking" aria-label="Permalink to &quot;C3 — 정렬·구조 (blocking)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>검사</th><th>규칙</th></tr></thead><tbody><tr><td>C3a 스펙 사이드바</td><td><code>blog/sidebar.specs.json</code> 각 그룹 <code>text</code> 선두 feature 번호가 <strong>내림차순</strong>(최신 먼저). 어긋난 인접쌍을 위반으로. <strong>BOM 제거 후</strong> 파싱하고, sync 구현에 따라 배열/<code>{value:[...]}</code> 객체 양쪽을 정규화(.ps1↔.sh 산출 형태 차이 흡수)</td></tr><tr><td>C3b 저널 정렬키</td><td>각 날짜-접두 저널의 <code>date</code>(없으면 <code>created</code>) 날짜부가 파일명 <code>YYYY-MM-DD-</code> 접두와 일치(= 자동 최신먼저 정렬 보장)</td></tr></tbody></table><blockquote><p>예외: <code>blog/llm/index.md</code>·사이드바의 **번호 오름차순(학습 순서)**은 의도된 예외로 C3 대상이 아니다(생성물이며 feature 012 결정).</p></blockquote><h2 id="c4-—-스타일-warning-종료-코드-무영향" tabindex="-1">C4 — 스타일 (warning, 종료 코드 무영향) <a class="header-anchor" href="#c4-—-스타일-warning-종료-코드-무영향" aria-label="Permalink to &quot;C4 — 스타일 (warning, 종료 코드 무영향)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>룰</th><th>트리거</th></tr></thead><tbody><tr><td>잔여 마커</td><td>본문에 <code>[NEEDS CLARIFICATION:</code>(콜론 있는 실제 마커)·<code>TODO</code>·<code>TKTK</code>·<code>&lt;placeholder&gt;</code>·<code>???</code></td></tr><tr><td>빈 링크</td><td><code>]( )</code> 또는 <code>]()</code></td></tr><tr><td>코드펜스 불균형</td><td>단독 라인 <code>```</code> 개수가 홀수</td></tr></tbody></table><p>전부 <strong>warning</strong> — 보고하되 <code>exitCode</code> 에 영향 없음. 코드펜스/인라인코드 내부는 마스킹 후 검사(오탐 최소화).</p><blockquote><p>오탐 회피 결정(dogfooding): ① <code>[NEEDS CLARIFICATION]</code>(콜론 없는 라벨, 체크리스트 가 정상적으로 사용)은 잔여 마커로 보지 않는다. ② <strong>H1 개수 룰은 제외</strong> — 저널· 콘텐츠가 frontmatter <code>title</code> 만 쓰고 본문 H1 을 두지 않는 본 저장소 관례 때문에 신호 대비 노이즈가 컸다.</p></blockquote><h2 id="종료-코드-규칙" tabindex="-1">종료 코드 규칙 <a class="header-anchor" href="#종료-코드-규칙" aria-label="Permalink to &quot;종료 코드 규칙&quot;">​</a></h2><p><code>exitCode = (C1~C3 위반 수 &gt; 0) ? 1 : 0</code>. C4 경고는 제외.</p>',21)])])}const p=e(a,[["render",r]]);export{g as __pageData,p as default};
